// agents/build/documentation-agent.js
// Takes all generated files. Produces README.md, CLAUDE.md template, inline comments.
// Returns: { readme: string, claude_md: string }

import { AgentBase } from '../../shared/agent-base-class.js'

class DocumentationAgent extends AgentBase {
  constructor() {
    super({ name: 'documentation-agent', phase: 'build', version: '1.0.0' })
  }

  async run(context) {
    const { spec, architectureSpec, generatedFiles } = context

    if (!spec) {
      throw new Error('documentation-agent requires spec in context')
    }

    const appName = spec.name || 'My App'
    const deployUrl = spec.deploy_url || 'https://yourdomain.com'
    const githubRepo = spec.github_repo || 'your-org/your-repo'

    this.log('info', 'Generating documentation', { app_name: appName })

    const readme = this._buildReadme(appName, deployUrl, githubRepo, spec, architectureSpec)
    const claude_md = this._buildClaudeMd(appName, spec, architectureSpec)

    this.log('info', 'Documentation generated', {
      readme_length: readme.length,
      claude_md_length: claude_md.length,
    })

    return { readme, claude_md }
  }

  _buildReadme(appName, deployUrl, githubRepo, spec, architectureSpec) {
    const description = spec?.description || `${appName} — your app, your rules.`
    const tables = architectureSpec?.database_tables || []
    const apiRoutes = architectureSpec?.api_routes || []
    const tier = spec?.tier || 'STANDARD'

    return `# ${appName}

${description}

**Live:** [${deployUrl}](${deployUrl})
**Repo:** [${githubRepo}](https://github.com/${githubRepo})

---

## Stack

- **Frontend:** React + Vite + TypeScript + Tailwind CSS
- **Backend:** Vercel Serverless Functions (Node ESM)
- **Database + Auth:** Supabase (PostgreSQL + Row Level Security)
- **Email:** Resend
- **Hosting:** Vercel

## Run locally

\`\`\`bash
git clone git@github.com:${githubRepo}.git
cd ${appName.toLowerCase().replace(/\s+/g, '-')}
npm install
cp .env.example .env
# Fill in .env with your Supabase and Resend credentials
npm run dev
\`\`\`

## Environment variables

See \`.env.example\` for the full list. Required:

- \`VITE_SUPABASE_URL\` — your Supabase project URL
- \`VITE_SUPABASE_ANON_KEY\` — Supabase anon/public key
- \`SUPABASE_URL\` — same as VITE_SUPABASE_URL (server-side)
- \`SUPABASE_SERVICE_ROLE_KEY\` — Supabase service role key (never expose client-side)
- \`RESEND_API_KEY\` — Resend API key for transactional email
- \`VITE_APP_URL\` — your public app URL (e.g. https://yourapp.com)

## Database

${tables.length > 0 ? `Tables: \`${tables.join('`, `')}\`\n\nAll tables have RLS enabled. Policies allow only authenticated users to access their own data.` : 'No database tables in this build.'}

## API routes

${apiRoutes.length > 0 ? apiRoutes.map(r => `- \`${r}\``).join('\n') : 'No API routes in this build.'}

## Security

- Row Level Security (RLS) enabled on every Supabase table
- All secrets server-side only — never in client bundles
- Rate limiting on every public API route
- CSP headers configured in \`vercel.json\`
- Soft deletes on all user data (deleted_at column)

## Ownership

You own this app completely. Source code, domain, database — everything is yours.
No lock-in. No Sovereign dependency at runtime.

Built with [Sovereign](https://sovereignapp.dev).
`
  }

  _buildClaudeMd(appName, spec, architectureSpec) {
    const tables = architectureSpec?.database_tables || []
    const tier = spec?.tier || 'STANDARD'
    const primaryColor = spec?.primaryColor || '#6366f1'

    return `# ${appName} — Claude Code Context

This app was generated by [Sovereign](https://sovereignapp.dev).

## Stack

- React + Vite + TypeScript + Tailwind CSS
- Supabase (auth + database + RLS)
- Vercel serverless functions (api/ directory, Node ESM)
- Resend for transactional email

## Commands

\`\`\`bash
npm run dev       # start dev server
npm run build     # production build (runs tsc + vite build)
npm run preview   # preview production build
\`\`\`

## Key files

- \`src/App.tsx\` — root component and router
- \`src/lib/supabase.ts\` — Supabase client
- \`src/types/index.ts\` — shared TypeScript types
- \`api/\` — serverless functions (one file per route)

## Database tables

${tables.length > 0 ? tables.map(t => `- \`${t}\``).join('\n') : 'None in this build.'}

All tables have RLS enabled. Use service role key (server-side only) for admin operations.

## Environment variables

See \`.env.example\`. Never commit \`.env\`.

## TypeScript rules (critical)

- Never use React namespace types: use \`import { type FormEvent } from 'react'\` not \`React.FormEvent\`
- Never use \`@/\` path aliases — use relative imports only
- Strings with apostrophes must use double quotes or template literals
- Every component must have a \`export default\` statement

## API route rules (critical)

- Every relative import must end with \`.js\` (Node ESM requirement)
- \`checkRateLimit\` must be the first logic call in every public handler
- \`export const config = { api: { bodyParser: { sizeLimit: '10mb' } } }\` required in every route
- Never log environment variable values — only length or status code

## Adding a new Supabase table

1. Write the SQL in Supabase SQL Editor:
   \`\`\`sql
   CREATE TABLE my_table (
     id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
     user_id UUID NOT NULL REFERENCES profiles(id),
     created_at TIMESTAMPTZ DEFAULT now(),
     deleted_at TIMESTAMPTZ DEFAULT NULL
   );
   ALTER TABLE my_table ENABLE ROW LEVEL SECURITY;
   CREATE POLICY "users_own_rows" ON my_table
     FOR ALL TO authenticated
     USING (user_id = auth.uid())
     WITH CHECK (user_id = auth.uid());
   \`\`\`
2. Confirm with: \`SELECT column_name FROM information_schema.columns WHERE table_name='my_table';\`
3. Add the type to \`src/types/index.ts\`
4. Create \`api/my_table/list.ts\` and \`api/my_table/create.ts\`

## Security rules

- RLS on every table — no exceptions
- Service role key only in \`api/\` files — never in \`src/\`
- Input validation on every API route before any DB call
- Soft deletes only — never hard-delete user data

## Brand tokens

- Primary: \`${primaryColor}\`
- Paper: \`#f2efe8\`
- Ink: \`#0e0d0b\`
- Fonts: Playfair Display (headings) + DM Mono (body)

## Contrast rules (WCAG AA)

Brightness formula: (R×299 + G×587 + B×114) / 1000
- > 128 = light background → use \`#1a1a1a\` text
- ≤ 128 = dark background → use \`#ffffff\` text

Hard-won lesson: never use \`#6b6862\` on dark backgrounds — only works on \`#f2efe8\`.
`
  }

  async verify(output) {
    if (!output.readme || output.readme.length < 200) {
      this.logIssue({
        severity: 'medium',
        message: 'README.md is too short — may be missing key sections',
        file: 'README.md',
      })
    }

    if (!output.claude_md || output.claude_md.length < 200) {
      this.logIssue({
        severity: 'medium',
        message: 'CLAUDE.md template is too short — may be missing key context',
        file: 'CLAUDE.md',
      })
    }

    // Check neither file has lorem ipsum
    const loremCheck = /lorem\s+ipsum/i
    if (loremCheck.test(output.readme) || loremCheck.test(output.claude_md)) {
      this.logIssue({
        severity: 'high',
        message: 'Documentation contains lorem ipsum placeholder text',
        file: 'README.md / CLAUDE.md',
      })
    }

    return output
  }
}

export default async function run(context) {
  return new DocumentationAgent().execute(context)
}
